#include <bits/stdc++.h>
using namespace std;
#define int long long

const int N = 2e5 + 5;

struct Cow {
    int v, x;
} a[N], t[N], L[N];

bool cmp_v(Cow a, Cow b) {
    if (a.v != b.v) return a.v < b.v;
    return a.x < b.x;
}

bool cmp_x(Cow a, Cow b) {
    return a.x < b.x;
}

int solve(int l, int r) {
    if (l >= r) return 0;

    int mid = (l + r) / 2;
    int res = solve(l, mid) + solve(mid + 1, r);

    int L_size = 0;
    for (int i = l; i <= mid; i++) {
        L[L_size++] = a[i];
    }
    sort(L, L + L_size, cmp_x);

    int sumL[L_size + 1], cntL[L_size + 1];
    sumL[0] = 0;
    cntL[0] = 0;
    for (int i = 0; i < L_size; i++) {
        sumL[i + 1] = sumL[i] + L[i].x;
        cntL[i + 1] = cntL[i] + 1;
    }

    for (int i = mid + 1; i <= r; i++) {
        int left = 0, right = L_size;
        while (left < right) {
            int m = (left + right) / 2;
            if (L[m].x < a[i].x) left = m + 1;
            else right = m;
        }
        int p = left;

        int cnt1 = p;
        int sum1 = sumL[p];
        res += a[i].v * (cnt1 * a[i].x - sum1);

        int cnt2 = L_size - p;
        int sum2 = sumL[L_size] - sumL[p];
        res += a[i].v * (sum2 - cnt2 * a[i].x);
    }

    int i = l, j = mid + 1, k = l;
    while (i <= mid && j <= r) {
        if (a[i].x < a[j].x) t[k++] = a[i++];
        else t[k++] = a[j++];
    }
    while (i <= mid) t[k++] = a[i++];
    while (j <= r) t[k++] = a[j++];

    for (int i = l; i <= r; i++) a[i] = t[i];

    return res;
}

signed main() {
    int n;
    cin >> n;

    for (int i = 0; i < n; i++) {
        cin >> a[i].v >> a[i].x;
    }

    sort(a, a + n, cmp_v);

    cout << solve(0, n - 1) << endl;

    return 0;
}
